    t = int(next(it))
    target = "abc"
    for _ in range(t):
        s = next(it)
        if s == target:
            print("YES")
            continue
        # At most one swap: just test all single swaps (and also original already handled)
        n = 3
        ok = False
        s_list = list(s)
        for i in range(n):
            for j in range(i + 1, n):
                s_list[i], s_list[j] = s_list[j], s_list[i]
                if "".join(s_list) == target:
                    ok = True
                s_list[i], s_list[j] = s_list[j], s_list[i]
                if ok:
                    break
            if ok:
                break
        print("YES" if ok else "NO")

